parameters.jsCode:
for (const item of $input.all()) {

  const baseUrl = item.json.url;
  const maxPages = parseInt(item.json.max_pages, 10);
  const pageFormatValue=item.json.page_format_value;

  const urls = [];

  for (let i = 1; i <= maxPages; i++) {
    urls.push(`${baseUrl}&${pageFormatValue}=${i}`);
  }

  item.json.generated_urls = urls;
}

return $input.all();

const items = $input.all();

const unified = items
  .flatMap(item => item.json.output || [])
  .flat();

return [
  {
    json: {
      unified_output: unified
    }
  }
];

